sql:
SELECT test_environment, COUNT(DISTINCT module_id) AS num_modules
FROM rf_measurements
GROUP BY test_environment;

SELECT module_name, model_number
FROM rf_modules
WHERE status = 'production';

SELECT DISTINCT module_id 
FROM rf_measurements 
WHERE test_environment = 'lab';

SELECT status, COUNT(*) 
FROM rf_modules 
GROUP BY status;

external_knowledge:
- In this context, 'current' refers to data with a test date matching the current date (today); 
- 'Details for RF Module A' includes its identifier, name, output power symbol, conditions, typical value, unit, output power stability symbol, value, unit, phase noise symbol, conditions, value, and unit; 
- 'For the user John Doe' signifies that the access log must be associated with this user.

sql:
SELECT MIN(value) AS minimum_output_power_stability
FROM rf_output_power_stability
WHERE condition_id = 1;

SELECT test_environment, COUNT(*) AS measurement_count
FROM rf_measurements
GROUP BY test_environment;
